{
  "compilerOptions": {
    "target": "ES2022",
    "module": "ES2022",
    "moduleResolution": "bundler",
    "esModuleInterop": true,
    "strict": true,
    "noEmit": true,
    "skipLibCheck": true
  },
  "include": ["skills/**/*.ts"]
}

import { readFileSync } from "node:fs";
import { Exa } from "exa-js";

/** Create an Exa client instance. Requires EXA_API_KEY env var. */
export function createClient(): Exa {
  return new Exa();
}

/** Require a CLI argument, exit with error if missing. */
export function requireArg(value: string | undefined, name: string): string {
  if (!value) {
    console.error(`Error: ${name} is required`);
    process.exit(1);
  }
  return value;
}

/** Execute an async API call, print JSON result, exit on error. */
export async function executeAndPrint<T>(apiCall: () => Promise<T>): Promise<void> {
  try {
    const result = await apiCall();
    console.log(JSON.stringify(result, null, 2));
  } catch (err) {
    handleError(err);
  }
}

/**
 * Show help text extracted from the JSDoc comment at the top of a script file.
 * Reads lines starting with " * " until " * /" is found.
 */
export function showHelp(scriptUrl: string): void {
  const lines: string[] = [];
  const src = readFileSync(new URL(scriptUrl), "utf8");
  for (const line of src.split("\n")) {
    if (line.startsWith(" * ") || line.startsWith(" */")) {
      if (line.startsWith(" */")) break;
      lines.push(line.slice(3));
    }
  }
  console.log(lines.join("\n"));
  process.exit(0);
}

/**
 * Ensure EXA_API_KEY is set. Exits with an error message if not.
 */
export function requireApiKey(): void {
  if (!process.env.EXA_API_KEY) {
    console.error("Error: EXA_API_KEY environment variable is required.");
    console.error("Get one at: https://dashboard.exa.ai/api-keys");
    process.exit(1);
  }
}

/**
 * Parse CLI args: show help if --help or no args, return query and options.
 */
export function parseArgs(scriptUrl: string): { query: string; opts: Record<string, unknown> } {
  const args = process.argv.slice(2);

  if (args.includes("--help") || args.length === 0) {
    showHelp(scriptUrl);
  }

  const query = args[0];
  const opts: Record<string, unknown> = args[1]
    ? (JSON.parse(args[1]) as Record<string, unknown>)
    : {};

  return { query, opts };
}

/**
 * Standardized error handler for all exa scripts.
 */
export function handleError(err: unknown): never {
  console.error(`Error: ${(err as Error).message}`);
  process.exit(1);
}

/**
 * Pick allowed keys from an options object, skipping undefined values.
 */
export function filterOptions(
  opts: Record<string, unknown>,
  keys: readonly string[],
): Record<string, unknown> {
  const filtered: Record<string, unknown> = {};
  for (const key of keys) {
    if (opts[key] !== undefined) filtered[key] = opts[key];
  }
  return filtered;
}

/**
 * Build contents options from text/highlights/summary fields.
 */
export function buildContentsOptions(opts: Record<string, unknown>): Record<string, unknown> {
  let contentsOpts: Record<string, unknown> = {};
  if (opts.text === true) contentsOpts.text = true;
  else if (typeof opts.text === "object") contentsOpts.text = opts.text;
  if (opts.highlights === true) contentsOpts.highlights = true;
  else if (typeof opts.highlights === "object") contentsOpts.highlights = opts.highlights;
  if (opts.summary === true) contentsOpts.summary = true;
  else if (typeof opts.summary === "object") contentsOpts.summary = opts.summary;
  if (typeof opts.contents === "object")
    contentsOpts = { ...contentsOpts, ...(opts.contents as Record<string, unknown>) };
  return contentsOpts;
}

#!/usr/bin/env tsx
/**
 * Exa answer — get AI-generated answers with citations.
 *
 * Usage:
 *   tsx scripts/answer.ts <query> [options-json]
 *   tsx scripts/answer.ts --help
 *
 * Options JSON (all optional):
 *   {
 *     "text": true,              // include full text in citation results
 *     "model": "exa",            // "exa" (default)
 *     "systemPrompt": "...",     // guide the LLM behavior
 *     "outputSchema": {},        // JSON Schema for structured output
 *     "stream": false,           // stream chunks to stdout
 *     "userLocation": "US"
 *   }
 *
 * Environment:
 *   EXA_API_KEY — required
 *
 * Examples:
 *   tsx scripts/answer.ts "What is the latest Next.js version?"
 *   tsx scripts/answer.ts "Compare React and Vue" '{"text":true}'
 *   tsx scripts/answer.ts "SpaceX valuation" '{"model":"exa","stream":true}'
 *   tsx scripts/answer.ts "List top 3 ORMs" '{"outputSchema":{"type":"object","properties":{"items":{"type":"array","items":{"type":"string"}}}}}'
 */

import {
  parseArgs,
  requireApiKey,
  handleError,
  filterOptions,
  createClient,
} from "./lib/common.js";

const { query, opts } = parseArgs(import.meta.url);
requireApiKey();

const exa = createClient();

const answerOpts = filterOptions(opts, [
  "text",
  "model",
  "systemPrompt",
  "outputSchema",
  "userLocation",
]);

try {
  if (opts.stream) {
    // Streaming mode — write chunks as they arrive
    for await (const chunk of exa.streamAnswer(query, answerOpts)) {
      const typedChunk = chunk as { content?: string; citations?: unknown };
      if (typedChunk.content) process.stdout.write(typedChunk.content);
      if (typedChunk.citations) {
        process.stdout.write("\n");
        console.log(JSON.stringify({ citations: typedChunk.citations }, null, 2));
      }
    }
    process.stdout.write("\n");
  } else {
    const result = await exa.answer(query, answerOpts);
    console.log(JSON.stringify(result, null, 2));
  }
} catch (err) {
  handleError(err);
}

#!/usr/bin/env tsx
/**
 * Exa get contents — retrieve page contents by URL.
 *
 * Usage:
 *   tsx scripts/contents.ts <url-or-urls-json> [options-json]
 *   tsx scripts/contents.ts --help
 *
 * First argument: a single URL string, or a JSON array of URLs.
 *
 * Options JSON (all optional):
 *   {
 *     "text": true,                         // or { "maxCharacters": 5000, "includeHtmlTags": false }
 *     "highlights": true,                   // or { "query": "AI", "numSentences": 3 }
 *     "summary": true,                      // or { "query": "summarize pricing" }
 *     "livecrawl": "auto",                  // "never"|"fallback"|"always"|"auto"|"preferred"
 *     "livecrawlTimeout": 10000,             // timeout in ms for live crawl
 *     "maxAgeHours": 168,                   // 0 = always fresh, -1 = cache only
 *     "filterEmptyResults": true,
 *     "subpages": 3,
 *     "subpageTarget": "pricing"
 *   }
 *
 * Environment:
 *   EXA_API_KEY — required
 *
 * Examples:
 *   tsx scripts/contents.ts "https://example.com/article"
 *   tsx scripts/contents.ts "https://example.com" '{"text":{"maxCharacters":2000}}'
 *   tsx scripts/contents.ts '["https://a.com","https://b.com"]' '{"text":true,"highlights":true}'
 */

import {
  showHelp,
  requireApiKey,
  filterOptions,
  createClient,
  executeAndPrint,
} from "./lib/common.js";

const args = process.argv.slice(2);

if (args.includes("--help") || args.length === 0) {
  showHelp(import.meta.url);
}

let urls: string | string[] = args[0];
try {
  urls = JSON.parse(urls) as string[];
} catch {
  // Single URL string — keep as-is
}

const opts: Record<string, unknown> = args[1]
  ? (JSON.parse(args[1]) as Record<string, unknown>)
  : { text: true };

requireApiKey();

const exa = createClient();

const contentsOpts = filterOptions(opts, [
  "text",
  "highlights",
  "summary",
  "livecrawl",
  "livecrawlTimeout",
  "maxAgeHours",
  "filterEmptyResults",
  "subpages",
  "subpageTarget",
]);

await executeAndPrint(async () => {
  return await exa.getContents(urls, contentsOpts);
});

#!/usr/bin/env tsx
/**
 * Exa find similar — find pages similar to a given URL.
 *
 * Usage:
 *   tsx scripts/find-similar.ts <url> [options-json]
 *   tsx scripts/find-similar.ts --help
 *
 * Options JSON (all optional):
 *   {
 *     "numResults": 10,
 *     "contents": true,               // true = text+highlights, or object for fine control
 *     "text": true,                    // shorthand: include text in results
 *     "highlights": true,              // shorthand: include highlights
 *     "summary": true,                 // shorthand: include summary
 *     "excludeSourceDomain": true,     // exclude the source domain from results
 *     "includeDomains": ["example.com"],
 *     "excludeDomains": ["spam.com"],
 *     "startPublishedDate": "2024-01-01T00:00:00.000Z",
 *     "endPublishedDate": "2025-01-01T00:00:00.000Z",
 *     "startCrawlDate": "2024-01-01T00:00:00.000Z",
 *     "endCrawlDate": "2025-01-01T00:00:00.000Z",
 *     "category": "news",
 *     "includeText": ["must contain"],
 *     "excludeText": ["must not contain"]
 *   }
 *
 * Environment:
 *   EXA_API_KEY — required
 *
 * Examples:
 *   tsx scripts/find-similar.ts "https://react.dev"
 *   tsx scripts/find-similar.ts "https://react.dev" '{"numResults":5,"text":true,"excludeSourceDomain":true}'
 */

import {
  parseArgs,
  requireApiKey,
  filterOptions,
  buildContentsOptions,
  createClient,
  executeAndPrint,
} from "./lib/common.js";

const { query: url, opts } = parseArgs(import.meta.url);
requireApiKey();

const exa = createClient();

const wantContents = opts.contents || opts.text || opts.highlights || opts.summary;

const contentsOpts = buildContentsOptions(opts);

const findSimilarKeys = [
  "numResults",
  "excludeSourceDomain",
  "includeDomains",
  "excludeDomains",
  "startCrawlDate",
  "endCrawlDate",
  "startPublishedDate",
  "endPublishedDate",
  "category",
  "includeText",
  "excludeText",
] as const;

const searchOpts = filterOptions(opts, findSimilarKeys);

await executeAndPrint(async () => {
  if (wantContents) {
    return await exa.findSimilarAndContents(url, { ...searchOpts, ...contentsOpts });
  } else {
    return await exa.findSimilar(url, searchOpts);
  }
});

#!/usr/bin/env tsx
/**
 * Exa research — create and manage deep research tasks.
 *
 * Usage:
 *   tsx scripts/research.ts create <instructions> [options-json]
 *   tsx scripts/research.ts get <research-id> [options-json]
 *   tsx scripts/research.ts poll <research-id> [options-json]
 *   tsx scripts/research.ts list [options-json]
 *   tsx scripts/research.ts run <instructions> [options-json]
 *   tsx scripts/research.ts --help
 *
 * Subcommands:
 *   create   — Start a new research task (returns immediately with researchId)
 *   get      — Get the current status/result of a research task
 *   poll     — Create and poll until finished (blocks until complete)
 *   list     — List research tasks
 *   run      — Create + poll in one step (convenience)
 *
 * Options JSON for create/run:
 *   {
 *     "model": "exa-research-fast",   // "exa-research-fast"|"exa-research"|"exa-research-pro"
 *     "outputSchema": {}              // JSON Schema for structured output
 *   }
 *
 * Options JSON for get:
 *   {
 *     "stream": false,                // stream SSE events
 *     "events": false                 // include event log
 *   }
 *
 * Options JSON for poll:
 *   {
 *     "pollInterval": 1000,           // ms between polls (default 1000)
 *     "timeoutMs": 600000,            // max wait time (default 10 min)
 *     "events": false
 *   }
 *
 * Options JSON for list:
 *   {
 *     "limit": 10,
 *     "cursor": "..."
 *   }
 *
 * Environment:
 *   EXA_API_KEY — required
 *
 * Examples:
 *   tsx scripts/research.ts create "Research the latest AI developments"
 *   tsx scripts/research.ts get "a1b2c3d4-e5f6-7890-abcd-ef1234567890"
 *   tsx scripts/research.ts run "What is SpaceX's latest valuation?" '{"model":"exa-research-pro"}'
 *   tsx scripts/research.ts list '{"limit":5}'
 */

import {
  showHelp,
  requireApiKey,
  handleError,
  requireArg,
  createClient,
} from "./lib/common.js";

const args = process.argv.slice(2);

if (args.includes("--help") || args.length === 0) {
  showHelp(import.meta.url);
}

const subcommand = args[0];
const arg1 = args[1];

requireApiKey();

const exa = createClient();

try {
  switch (subcommand) {
    case "create": {
      const instructions = requireArg(arg1, "instructions");
      const opts: Record<string, unknown> = args[2]
        ? (JSON.parse(args[2]) as Record<string, unknown>)
        : {};
      const result = await exa.research.create({
        instructions,
        model:
          (opts.model as "exa-research-fast" | "exa-research" | "exa-research-pro") ?? undefined,
        outputSchema: (opts.outputSchema as Record<string, unknown>) ?? undefined,
      });
      console.log(JSON.stringify(result, null, 2));
      break;
    }

    case "get": {
      const researchId = requireArg(arg1, "research-id");
      const opts: Record<string, unknown> = args[2]
        ? (JSON.parse(args[2]) as Record<string, unknown>)
        : {};
      if (opts.stream) {
        const streamResult = await exa.research.get(researchId, { stream: true, ...opts });
        for await (const event of streamResult) {
          console.log(JSON.stringify(event));
        }
      } else {
        const result = await exa.research.get(researchId, opts);
        console.log(JSON.stringify(result, null, 2));
      }
      break;
    }

    case "poll": {
      const researchId = requireArg(arg1, "research-id");
      const opts: Record<string, unknown> = args[2]
        ? (JSON.parse(args[2]) as Record<string, unknown>)
        : {};
      const result = await exa.research.pollUntilFinished(researchId, opts);
      console.log(JSON.stringify(result, null, 2));
      break;
    }

    case "run": {
      const instructions = requireArg(arg1, "instructions");
      const opts: Record<string, unknown> = args[2]
        ? (JSON.parse(args[2]) as Record<string, unknown>)
        : {};
      const created = await exa.research.create({
        instructions,
        model:
          (opts.model as "exa-research-fast" | "exa-research" | "exa-research-pro") ?? undefined,
        outputSchema: (opts.outputSchema as Record<string, unknown>) ?? undefined,
      });
      const createdTyped = created as { researchId: string };
      console.error(`Research task created: ${createdTyped.researchId} — polling...`);
      const result = await exa.research.pollUntilFinished(createdTyped.researchId, {
        pollInterval: (opts.pollInterval as number) || 2000,
        timeoutMs: (opts.timeoutMs as number) || 600000,
        events: opts.events as boolean | undefined,
      });
      console.log(JSON.stringify(result, null, 2));
      break;
    }

    case "list": {
      const opts: Record<string, unknown> = arg1
        ? (JSON.parse(arg1) as Record<string, unknown>)
        : {};
      const result = await exa.research.list(opts);
      console.log(JSON.stringify(result, null, 2));
      break;
    }

    default:
      console.error(`Error: Unknown subcommand "${subcommand}".`);
      console.error("Valid subcommands: create, get, poll, list, run");
      process.exit(1);
  }
} catch (err) {
  handleError(err);
}

#!/usr/bin/env node

import path from 'node:path';
import fs from 'node:fs';
import { fileURLToPath } from 'node:url';
import { getFixture } from './lib/fixtures.js';
import * as spec from './lib/dashboard-spec.js';
import { createClient, PostHogError } from './lib/posthog-client.js';
import type { PostHogConfig } from './lib/posthog-client.js';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

// ---------------------------------------------------------------------------
// Config resolution
// ---------------------------------------------------------------------------

interface AppConfig extends PostHogConfig {
  achInsightId: string;
  dashboardName: string;
}

function resolveConfig(): AppConfig {
  return {
    host: process.env['POSTHOG_HOST'] ?? 'https://us.posthog.com',
    projectId: process.env['POSTHOG_PROJECT_ID'] ?? '39507',
    token: process.env['POSTHOG_PERSONAL_API_KEY'] ?? '',
    achInsightId: process.env['POSTHOG_ACH_INSIGHT_ID'] ?? 'drOq2lO5',
    dashboardName: process.env['POSTHOG_DASHBOARD_NAME'] ?? spec.name,
  };
}

function requireToken(config: AppConfig): void {
  if (!config.token) {
    process.stderr.write(
      'Error: POSTHOG_PERSONAL_API_KEY is required for this command.\n' +
        'Set it in your environment: export POSTHOG_PERSONAL_API_KEY=phx_...\n',
    );
    process.exit(1);
  }
}

// ---------------------------------------------------------------------------
// Output helpers
// ---------------------------------------------------------------------------

function out(data: unknown): void {
  process.stdout.write(JSON.stringify(data, null, 2) + '\n');
}

function info(msg: string): void {
  process.stderr.write(msg + '\n');
}

function handleApiError(err: unknown, context?: string): never {
  if (err instanceof PostHogError) {
    if (err.status === 401) {
      process.stderr.write(
        `Error: PostHog returned 401 (Unauthorized) on ${err.endpoint}\n` +
          'Verify that POSTHOG_PERSONAL_API_KEY is valid and has not expired.\n',
      );
    } else if (err.status === 403) {
      process.stderr.write(
        `Error: PostHog returned 403 (Forbidden) on ${err.endpoint}\n` +
          'Check that your API key has these scopes: dashboard:read, dashboard:write, insight:read, insight:write, query:read\n',
      );
    } else if (err.status === 429) {
      process.stderr.write(
        `Error: PostHog rate limit exceeded on ${err.endpoint} — tried 3 times.\n`,
      );
    } else {
      process.stderr.write(`Error: ${context ?? 'PostHog request failed'}: ${err.message}\n`);
    }
  } else {
    const message = err instanceof Error ? err.message : String(err);
    process.stderr.write(`Error: Connection to PostHog failed: ${message}\n`);
  }
  process.exit(1);
}

// ---------------------------------------------------------------------------
// Commands
// ---------------------------------------------------------------------------

function cmdStatus(config: AppConfig): void {
  const tokenDisplay = config.token
    ? `***${config.token.slice(-4)} (present)`
    : 'NOT SET';
  const achDisplay = config.achInsightId || 'NOT SET';

  out({
    host: config.host,
    project_id: config.projectId,
    token: tokenDisplay,
    token_present: Boolean(config.token),
    ach_insight_id: achDisplay,
    dashboard_name: config.dashboardName,
  });
}

async function cmdInspect(flags: string[], config: AppConfig): Promise<void> {
  const isDryRun = flags.includes('--dry-run');
  const isLive = flags.includes('--live');

  if (isDryRun) {
    out(getFixture('inspect'));
    return;
  }

  if (isLive) {
    requireToken(config);
    await cmdInspectLive(config);
    return;
  }

  // Static local spec — works offline
  out({
    source: 'local-spec',
    events: spec.branchEvents.map((ev) => ({
      name: ev.name,
      description: ev.description,
      properties: ev.properties,
    })),
  });
}

async function cmdInspectLive(config: AppConfig): Promise<void> {
  const client = createClient(config);
  const eventNames = spec.branchEvents.map((ev) => ev.name);

  const quotedNames = eventNames.map((n) => `'${n}'`).join(', ');
  const sql = [
    'SELECT',
    '  event,',
    '  count() AS count_30d,',
    '  max(timestamp) AS last_seen',
    'FROM events',
    `WHERE event IN (${quotedNames})`,
    '  AND timestamp >= now() - INTERVAL 30 DAY',
    'GROUP BY event',
  ].join('\n');

  const startMs = Date.now();
  let queryResult;
  try {
    queryResult = await client.runQuery(sql);
  } catch (err) {
    handleApiError(err, 'inspect --live query failed');
  }

  const elapsed = Date.now() - startMs;
  info(`PostHog query completed in ${elapsed}ms (cached: ${queryResult.is_cached ?? false})`);

  // Build map from results: event → { count_30d, last_seen }
  // HogQL returns rows as arrays; columns order: event, count_30d, last_seen
  const map: Record<string, { count_30d: unknown; last_seen: unknown }> = {};
  const rows = queryResult.results ?? [];
  for (const row of rows) {
    const eventName = row[0];
    if (typeof eventName === 'string') {
      map[eventName] = {
        count_30d: row[1] ?? 0,
        last_seen: row[2] ?? null,
      };
    }
  }

  // Zero-fill for events not present in result
  const events = eventNames.map((name) => ({
    event: name,
    count_30d: map[name] !== undefined ? map[name].count_30d : 0,
    last_seen: map[name] !== undefined ? map[name].last_seen : null,
  }));

  out({
    source: 'posthog-live',
    queried_at: new Date().toISOString(),
    events,
  });
}

async function cmdCompare(flags: string[], config: AppConfig): Promise<void> {
  const isDryRun = flags.includes('--dry-run');

  if (isDryRun) {
    out(getFixture('compare'));
    return;
  }

  requireToken(config);
  await cmdCompareLive(config);
}

async function cmdCompareLive(config: AppConfig): Promise<void> {
  const client = createClient(config);
  const shortId = config.achInsightId;

  let response;
  try {
    response = await client.getInsightByShortId(shortId);
  } catch (err) {
    handleApiError(err, `compare: failed to fetch insight ${shortId}`);
  }

  const results = response.results ?? [];
  if (results.length === 0) {
    process.stderr.write(
      `Error: ACH insight not found: ${shortId} — verify the short ID is correct and the token has insight:read scope\n`,
    );
    process.exit(1);
  }

  const insight = results[0];
  if (!insight) {
    process.exit(1);
  }

  const rawQuery: Record<string, unknown> = insight.query ?? {};

  // PostHog wraps newer queries in InsightVizNode; drill into .source for actual query data
  const isVizNode = rawQuery['kind'] === 'InsightVizNode';
  const querySource = rawQuery['source'];
  const query: Record<string, unknown> = isVizNode
    ? typeof querySource === 'object' && querySource !== null
      ? (querySource as Record<string, unknown>)
      : {}
    : rawQuery;

  // Extract viz_type: funnels store it in funnelsFilter, trends in trendsFilter
  let vizType: string | null = null;
  const funnelsFilter = query['funnelsFilter'];
  const trendsFilter = query['trendsFilter'];
  const insightFilters = insight.filters;

  if (typeof funnelsFilter === 'object' && funnelsFilter !== null) {
    const ff = funnelsFilter as Record<string, unknown>;
    if (ff['funnelVizType']) {
      vizType = `funnel:${String(ff['funnelVizType'])}`;
    }
  } else if (typeof trendsFilter === 'object' && trendsFilter !== null) {
    const tf = trendsFilter as Record<string, unknown>;
    if (tf['display']) {
      vizType = String(tf['display']);
    }
  } else if (typeof insightFilters === 'object' && insightFilters !== null) {
    const ifd = (insightFilters as Record<string, unknown>)['display'];
    if (ifd) {
      vizType = String(ifd);
    }
  }

  // Extract normalized summary fields
  const seriesRaw = query['series'];
  const series = Array.isArray(seriesRaw)
    ? seriesRaw.map((s: unknown) => {
        const item = s as Record<string, unknown>;
        return { event: item['event'], name: item['name'], kind: item['kind'] };
      })
    : [];

  const breakdownFilter = query['breakdownFilter'];
  const breakdown =
    typeof breakdownFilter === 'object' && breakdownFilter !== null
      ? (breakdownFilter as Record<string, unknown>)['breakdown'] ?? null
      : null;

  const dateRange = query['dateRange'];
  const dateRangeFrom =
    typeof dateRange === 'object' && dateRange !== null
      ? (dateRange as Record<string, unknown>)['date_from'] ?? null
      : null;

  const queryKindInner = query['kind'];
  const rawQueryKind = rawQuery['kind'];

  const summary = {
    id: insight.short_id ?? shortId,
    name: insight.name ?? null,
    description: insight.description ?? null,
    query_kind: isVizNode
      ? `InsightVizNode(${typeof queryKindInner === 'string' ? queryKindInner : '?'})`
      : typeof rawQueryKind === 'string'
        ? rawQueryKind
        : null,
    series,
    breakdown,
    date_range: dateRangeFrom,
    viz_type: vizType,
    saved_to: 'references/ach-reference-summary.json',
  };

  // Write to references/ach-reference-summary.json
  const summaryPath = path.join(__dirname, '..', 'references', 'ach-reference-summary.json');
  try {
    fs.writeFileSync(summaryPath, JSON.stringify(summary, null, 2) + '\n', 'utf8');
  } catch (writeErr) {
    const msg = writeErr instanceof Error ? writeErr.message : String(writeErr);
    process.stderr.write(`Warning: could not write ${summaryPath}: ${msg}\n`);
  }

  out(summary);
}

async function cmdCreate(flags: string[], config: AppConfig): Promise<void> {
  const isDryRun = flags.includes('--dry-run');

  if (isDryRun) {
    out(getFixture('create'));
    return;
  }

  requireToken(config);
  await cmdCreateLive(config);
}

async function cmdCreateLive(config: AppConfig): Promise<void> {
  const client = createClient(config);
  const dashboardName = config.dashboardName;
  const host = config.host;
  const projectId = config.projectId;

  // Step 1: Smoke test auth
  try {
    await client.listDashboards(1);
  } catch (err) {
    if (err instanceof PostHogError && err.status === 401) {
      process.stderr.write('Error: auth failed — verify POSTHOG_PERSONAL_API_KEY is valid.\n');
    } else if (err instanceof PostHogError && err.status === 403) {
      process.stderr.write(
        'Error: PostHog returned 403 — check that your API key has dashboard:read, dashboard:write, insight:read, insight:write, query:read scopes\n',
      );
    } else {
      const msg = err instanceof Error ? err.message : String(err);
      process.stderr.write(`Error: connection failed: ${msg}\n`);
    }
    process.exit(1);
  }

  // Step 2: List dashboards (up to 100)
  let dashboardList;
  try {
    dashboardList = await client.listDashboards(100);
  } catch (err) {
    handleApiError(err, 'create: failed to list dashboards');
  }

  const allDashboards = dashboardList.results ?? [];
  if (dashboardList.count > 100) {
    info('Warning: dashboard list may be truncated at 100 results');
  }

  // Step 3: Find or create dashboard
  const existing = allDashboards.find((d) => d.name === dashboardName && !d.deleted);
  let dashboardId: number;

  if (existing) {
    dashboardId = existing.id;
    info(`Found existing dashboard "${dashboardName}" (id: ${dashboardId})`);
  } else {
    info(`Creating dashboard "${dashboardName}"...`);
    let created;
    try {
      created = await client.createDashboard(dashboardName, spec.tags);
    } catch (err) {
      handleApiError(err, 'create: failed to create dashboard');
    }
    dashboardId = created.id;
    info(`Dashboard created (id: ${dashboardId})`);
  }

  // Step 4: Fetch full dashboard (includes tiles with nested insights)
  let dashboard;
  try {
    dashboard = await client.getDashboard(dashboardId);
  } catch (err) {
    handleApiError(err, `create: failed to fetch dashboard ${dashboardId}`);
  }

  // Step 5: Build existing insight name → tile map from dashboard tiles
  const existingTiles = dashboard.tiles ?? [];
  type ExistingTile = (typeof existingTiles)[number];
  const existingNameToTile: Record<string, ExistingTile> = {};
  for (const tile of existingTiles) {
    if (tile.insight && tile.insight.name) {
      existingNameToTile[tile.insight.name] = tile;
    }
  }

  // Step 6: Create missing insights, attaching them to the dashboard via dashboards:[id]
  // Insights created with dashboards:[dashboardId] are auto-attached — no PATCH needed.
  const tileResults: Array<{
    specTile: (typeof spec.tiles)[number];
    insightId: number | null;
    status: 'existing' | 'created' | 'failed';
  }> = [];
  let hasFailure = false;

  for (const specTile of spec.tiles) {
    const existingTile = existingNameToTile[specTile.name];

    if (existingTile) {
      const tileInsight = existingTile.insight;
      if (tileInsight) {
        info(`Skipping existing insight: "${specTile.name}" (id: ${tileInsight.id})`);
        tileResults.push({
          specTile,
          insightId: tileInsight.id,
          status: 'existing',
        });
      }
      continue;
    }

    info(`Creating insight: "${specTile.name}"...`);
    try {
      const newInsight = await client.createInsightOnDashboard(
        specTile.name,
        specTile.query,
        dashboardId,
      );
      info(`  Created insight (id: ${newInsight.id})`);
      tileResults.push({
        specTile,
        insightId: newInsight.id,
        status: 'created',
      });
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      process.stderr.write(`Error creating insight "${specTile.name}": ${msg}\n`);
      tileResults.push({
        specTile,
        insightId: null,
        status: 'failed',
      });
      hasFailure = true;
    }
  }

  // Step 7: Emit result (no PATCH needed — insights attach via dashboards field)
  const tiles = tileResults.map((t) => ({
    name: t.specTile.name,
    insight_id: t.insightId,
    insight_url:
      t.insightId !== null
        ? `${host}/project/${projectId}/insights/${t.insightId}`
        : null,
    status: t.status,
  }));

  out({
    dashboard_id: dashboardId,
    dashboard_url: `${host}/project/${projectId}/dashboard/${dashboardId}`,
    tiles,
  });

  if (hasFailure) {
    process.exit(3);
  }
}

// ---------------------------------------------------------------------------
// Flags command
// ---------------------------------------------------------------------------

interface FlagsOptions {
  search?: string;
  active?: string;
  type?: string;
  limit?: string;
  name?: string;
  tags?: string;
  dryRun: boolean;
}

function parseFlagsOptions(args: string[]): FlagsOptions {
  const opts: FlagsOptions = { dryRun: false };
  let i = 0;
  while (i < args.length) {
    const arg = args[i];
    if (arg === undefined) break;
    switch (arg) {
      case '--dry-run':
        opts.dryRun = true;
        i++;
        break;
      case '--search':
        opts.search = args[i + 1];
        i += 2;
        break;
      case '--active':
        opts.active = args[i + 1];
        i += 2;
        break;
      case '--type':
        opts.type = args[i + 1];
        i += 2;
        break;
      case '--limit':
        opts.limit = args[i + 1];
        i += 2;
        break;
      case '--name':
        opts.name = args[i + 1];
        i += 2;
        break;
      case '--tags':
        opts.tags = args[i + 1];
        i += 2;
        break;
      default:
        i++;
    }
  }
  return opts;
}

async function cmdFlags(args: string[], config: AppConfig): Promise<void> {
  // Determine subcommand: if first arg starts with '--' or is missing, default to 'list'
  let subcommand = 'list';
  let rest = args;
  const firstArg = args[0];
  if (firstArg !== undefined && !firstArg.startsWith('--')) {
    subcommand = firstArg;
    rest = args.slice(1);
  }

  const opts = parseFlagsOptions(rest);

  switch (subcommand) {
    case 'list': {
      if (opts.dryRun) {
        out(getFixture('flags'));
        return;
      }
      requireToken(config);
      const client = createClient(config);
      try {
        const result = await client.listFeatureFlags({
          search: opts.search,
          active: opts.active,
          type: opts.type,
          limit: opts.limit !== undefined ? Number(opts.limit) : undefined,
        });
        out(result);
      } catch (err) {
        handleApiError(err, 'flags list failed');
      }
      break;
    }
    case 'get': {
      const id = rest.find((a) => !a.startsWith('--'));
      if (!id) {
        process.stderr.write('Error: flags get requires a flag ID — ID is required\n');
        process.exit(2);
      }
      if (opts.dryRun) {
        out(getFixture('flags-get'));
        return;
      }
      requireToken(config);
      const client = createClient(config);
      try {
        const result = await client.getFeatureFlag(id);
        out(result);
      } catch (err) {
        handleApiError(err, `flags get ${id} failed`);
      }
      break;
    }
    case 'toggle': {
      const id = rest.find((a) => !a.startsWith('--'));
      if (!id) {
        process.stderr.write('Error: flags toggle requires a flag ID\n');
        process.exit(2);
      }
      if (opts.dryRun) {
        out(getFixture('flags-toggle'));
        return;
      }
      requireToken(config);
      const client = createClient(config);
      try {
        const current = await client.getFeatureFlag(id);
        await client.patchFeatureFlag(id, { active: !current.active });
        out({
          id: current.id,
          key: current.key,
          active_before: current.active,
          active_after: !current.active,
        });
      } catch (err) {
        handleApiError(err, `flags toggle ${id} failed`);
      }
      break;
    }
    case 'create': {
      const key = rest.find((a) => !a.startsWith('--'));
      if (!key) {
        process.stderr.write('Error: flags create requires a flag key\n');
        process.exit(2);
      }
      if (opts.dryRun) {
        out(getFixture('flags-create'));
        return;
      }
      requireToken(config);
      const client = createClient(config);
      try {
        const body: Record<string, unknown> = { name: opts.name };
        if (opts.tags !== undefined) {
          body['tags'] = opts.tags.split(',');
        }
        const result = await client.createFeatureFlag(key, body);
        out(result);
      } catch (err) {
        handleApiError(err, `flags create ${key} failed`);
      }
      break;
    }
    case 'update': {
      const id = rest.find((a) => !a.startsWith('--'));
      if (!id) {
        process.stderr.write('Error: flags update requires a flag ID\n');
        process.exit(2);
      }
      if (opts.dryRun) {
        out(getFixture('flags-update'));
        return;
      }
      requireToken(config);
      const client = createClient(config);
      try {
        const body: Record<string, unknown> = {};
        if (opts.name !== undefined) body['name'] = opts.name;
        if (opts.active !== undefined) body['active'] = opts.active === 'true';
        if (opts.tags !== undefined) body['tags'] = opts.tags.split(',');
        const result = await client.patchFeatureFlag(id, body);
        out(result);
      } catch (err) {
        handleApiError(err, `flags update ${id} failed`);
      }
      break;
    }
    case 'activity': {
      const id = rest.find((a) => !a.startsWith('--'));
      if (!id) {
        process.stderr.write('Error: flags activity requires a flag ID\n');
        process.exit(2);
      }
      if (opts.dryRun) {
        out(getFixture('flags-activity'));
        return;
      }
      requireToken(config);
      const client = createClient(config);
      try {
        const result = await client.getFeatureFlagActivity(
          id,
          opts.limit !== undefined ? Number(opts.limit) : 10,
        );
        out(result);
      } catch (err) {
        handleApiError(err, `flags activity ${id} failed`);
      }
      break;
    }
    default:
      process.stderr.write(`Unknown flags subcommand: ${subcommand}\n`);
      process.exit(2);
  }
}

